# ── [SECTION: UTILITY FUNCTIONS] ────────────────────────────────
def get_week_key():
    now = datetime.now(timezone.utc)
    return f"{now.year}-W{now.strftime('%W')}"

def ask_groq(prompt, max_tokens=600):
    # Uses versatile model for all intelligence briefs
    r = groq_client.chat.completions.create(
        model="llama-3.3-70b-versatile",
        messages=[{"role": "user", "content": prompt}],
        max_tokens=max_tokens, temperature=0.3
    )
    return r.choices[0].message.content

def sanitize(text):
    # Replaces unicode characters that fpdf2 cannot handle
    # Called on ALL text before writing to PDF
    if not text:
        return ""
    replacements = {
        "\u2014": "-", "\u2013": "-", "\u2012": "-",
        "\u2018": "'", "\u2019": "'", "\u201a": "'",
        "\u201c": '"', "\u201d": '"', "\u201e": '"',
        "\u2022": "*", "\u2023": "*", "\u25aa": "*",
        "\u2026": "...", "\u00a0": " ", "\u2032": "'",
        "\u00e9": "e", "\u00e8": "e", "\u00ea": "e",
        "\u00e0": "a", "\u00e2": "a", "\u00f4": "o",
        "\u00fb": "u", "\u00fc": "u", "\u00ef": "i",
        "\u00e7": "c", "\u00f1": "n",
    }
    for orig, repl in replacements.items():
        text = text.replace(orig, repl)
    text = text.encode("latin-1", errors="replace").decode("latin-1")
    # Break words longer than 60 chars to prevent fpdf crash
    words = text.split(" ")
    broken = []
    for w in words:
        if len(w) > 60:
            broken.append(w[:60] + " " + w[60:])
        else:
            broken.append(w)
    return " ".join(broken)

def pdf_write_line(pdf, line):
    # Safe single-line writer for PDF — wraps in try/except
    # Detects header lines vs body lines for styling
    line = line.strip()
    if not line:
        pdf.ln(3)
        return
    is_header = any(line.startswith(x) for x in [
        "STORY", "BOTTOM LINE", "WEEK", "EXECUTIVE",
        "STRATEGIC RISK", "HIGH RISK", "MEDIUM RISK", "OPPORTUNITY"
    ])
    if is_header:
        pdf.set_font("Helvetica", "B", 10)
        pdf.set_text_color(232, 213, 163)
    else:
        pdf.set_font("Helvetica", "", 10)
        pdf.set_text_color(180, 195, 210)
    try:
        pdf.multi_cell(0, 6, line)
    except Exception:
        try:
            pdf.multi_cell(0, 6, line[:200])
        except Exception:
            pass
# ── [END: UTILITY FUNCTIONS] ────────────────────────────────────


